UPDATE `gen_template` SET `template_content` = 'import { requestClient } from \'#/api/request\';\n\nexport async function get${className}Page(data: any) {\n  return requestClient.post(\'/${moduleName}/${requestName}/index\', data);\n}\n\nexport async function get${className}RecyclePage(data: any) {\n  return requestClient.post(\'/${moduleName}/${requestName}/recycle\', data);\n}\n\nexport async function create${className}(data: any) {\n  return requestClient.post(\'/${moduleName}/${requestName}/create\', data);\n}\n\nexport async function update${className}(data: any) {\n  return requestClient.put(\'/${moduleName}/${requestName}/update\', data);\n}\n\nexport async function delete${className}(data: any) {\n  return requestClient.post(\'/${moduleName}/${requestName}/delete\', null, {\n    params: {\n      ids: data,\n    },\n  });\n}\n\nexport async function restore${className}(data: any) {\n  return requestClient.post(\'/${moduleName}/${requestName}/restore\', null, {\n    params: {\n      ids: data,\n    },\n  });\n}\n\nexport async function wipe${className}(data: any) {\n  return requestClient.delete(\'/${moduleName}/${requestName}/wipe\', {\n    params: {\n      ids: data,\n    },\n  });\n}\n', `update_time` = NOW() WHERE `template_name` = 'api.ts';
UPDATE `gen_template` SET `template_content` = 'package ${packageName}.application.service.${moduleName}.dto;\n\nimport lombok.Data;\nimport java.io.Serializable;\n<#assign javaLangTypes = ["String", "Long", "Integer", "Boolean", "Double", "Float", "Short", "Byte", "Character"]>\n<#assign importPackages = {"LocalDateTime":"java.time", "LocalDate":"java.time", "LocalTime":"java.time", "Instant":"java.time", "ZonedDateTime":"java.time", "Duration":"java.time", "Period":"java.time", "BigDecimal":"java.math", "BigInteger":"java.math", "Date":"java.util", "Timestamp":"java.sql", "UUID":"java.util"}>\n<#assign imports = []>\n<#list columnsViews as property>\n    <#if !(["createBy", "createTime", "updateBy", "updateTime", "version", "create_by", "create_time", "update_by", "update_time"]?seq_contains(property.propJavaEntity))>\n      <#assign type = property.propJavaType>\n      <#if !(javaLangTypes?seq_contains(type)) && importPackages[type]?? && !(imports?seq_contains(type))>\n        <#assign imports += [type]>\n      </#if>\n    </#if>\n</#list>\n<#list imports as imp>\nimport ${importPackages[imp]}.${imp};\n</#list>\n\n@Data\npublic class ${className}Command implements Serializable {\n    <#assign excludeFields = ["createBy", "createTime", "updateBy", "updateTime", "version", "deptId", "dept_id", "create_by", "create_time", "update_by", "update_time"]>\n\n    <#list columnsViews as property>\n        <#if !(excludeFields?seq_contains(property.propJavaEntity))>\n    private ${property.propJavaType} ${property.propJavaEntity};\n\n        </#if>\n    </#list>\n}\n', `update_time` = NOW() WHERE `template_name` = 'command';
UPDATE `gen_template` SET `template_content` = 'package ${packageName}.application.service.${moduleName};\n\nimport ${packageName}.application.service.${moduleName}.dto.${className}Command;\nimport ${packageName}.domain.${moduleName}.*;\nimport lombok.RequiredArgsConstructor;\nimport org.springframework.stereotype.Service;\nimport reactor.core.publisher.Mono;\n\nimport java.util.List;\n\n@Service\n@RequiredArgsConstructor\npublic class ${className}CommandService {\n\n    private final ${className}DomainRepository ${requestName}DomainRepository;\n\n    private final ${className}DomainFactory ${requestName}DomainFactory;\n\n    private final Delete${className}DomainService delete${className}DomainService;\n\n    private final Restore${className}DomainService restore${className}DomainService;\n\n    private final Wipe${className}DomainService wipe${className}DomainService;\n\n    public Mono<Long> create(${className}Command command) {\n    <#assign newInstanceParams = []>\n    <#assign commandExcludeFields = ["createBy", "createTime", "updateBy", "updateTime", "version", "create_by", "create_time", "update_by", "update_time"]>\n    <#list aggregateViews as aggregateView>\n        <#if aggregateView.objectType != 1 && aggregateView.objectType != 4>\n            <#assign fieldList = aggregateView.objectValue?replace(\'"\', \'\')?replace(\'[\', \'\')?replace(\']\', \'\')?split(",")>\n            <#assign constructorParams = []>\n            <#list fieldList as field>\n                <#assign fieldTrimmed = field?trim>\n                <#if commandExcludeFields?seq_contains(fieldTrimmed)>\n                    <#assign constructorParams += ["null"]>\n                <#else>\n                    <#list columnsViews as col>\n                        <#if col.propJavaEntity == fieldTrimmed>\n                            <#assign constructorParams += ["command.get" + fieldTrimmed?cap_first + "()"]>\n                        </#if>\n                    </#list>\n                </#if>\n            </#list>\n            <#assign varName = aggregateView.objectName?uncap_first>\n        ${aggregateView.objectName} ${varName} = new ${aggregateView.objectName}(${constructorParams?join(", ")});\n            <#assign newInstanceParams += [varName]>\n        </#if>\n    </#list>\n\n        ${className}Domain domain = ${requestName}DomainFactory.newInstance(${newInstanceParams?join(", ")});\n        domain.create();\n        return ${requestName}DomainRepository.save(domain);\n    }\n\n    public Mono<Void> update(${className}Command command) {\n        <#assign updateParams = []>\n        <#assign commandExcludeFields = ["createBy", "createTime", "updateBy", "updateTime", "version", "create_by", "create_time", "update_by", "update_time"]>\n        <#list aggregateViews as aggregateView>\n            <#if aggregateView.objectType != 1 && aggregateView.objectType != 4>\n                <#assign fieldList = aggregateView.objectValue?replace(\'"\', \'\')?replace(\'[\', \'\')?replace(\']\', \'\')?split(",")>\n                <#assign constructorParams = []>\n                <#list fieldList as field>\n                    <#assign fieldTrimmed = field?trim>\n                    <#if commandExcludeFields?seq_contains(fieldTrimmed)>\n                        <#assign constructorParams += ["null"]>\n                    <#else>\n                        <#list columnsViews as col>\n                            <#if col.propJavaEntity == fieldTrimmed>\n                                <#assign constructorParams += ["command.get" + fieldTrimmed?cap_first + "()"]>\n                            </#if>\n                        </#list>\n                    </#if>\n                </#list>\n                <#assign varName = aggregateView.objectName?uncap_first>\n        ${aggregateView.objectName} ${varName} = new ${aggregateView.objectName}(${constructorParams?join(", ")});\n                <#assign updateParams += [varName]>\n            </#if>\n        </#list>\n\n        <#list aggregateViews as aggregateView>\n            <#if aggregateView.objectType == 1>\n        return ${requestName}DomainRepository.load(new ${aggregateView.objectName}(command.getId()))\n                .flatMap(domain -> {\n                    domain.update(${updateParams?join(", ")});\n                    return ${requestName}DomainRepository.save(domain);\n                }).then();\n            <#break>\n            </#if>\n        </#list>\n    }\n\n    public Mono<Void> delete(List<Long> ids) {\n        return delete${className}DomainService.deleteByIds(ids);\n    }\n\n    public Mono<Void> restore(List<Long> ids) {\n        return restore${className}DomainService.restoreByIds(ids);\n    }\n\n    public Mono<Void> wipe(List<Long> ids) {\n        return wipe${className}DomainService.wipeByIds(ids);\n    }\n}\n', `update_time` = NOW() WHERE `template_name` = 'commandService';
UPDATE `gen_template` SET `template_content` = 'package ${packageName}.web;\n\nimport ${packageName}.application.service.${moduleName}.${className}CommandService;\nimport ${packageName}.application.service.${moduleName}.${className}QueryService;\nimport ${packageName}.application.service.${moduleName}.dto.${className}Command;\nimport ${packageName}.application.service.${moduleName}.dto.${className}PageQuery;\nimport ${packageName}.domain.util.ApiResponse;\nimport jakarta.validation.Valid;\nimport lombok.RequiredArgsConstructor;\nimport org.springframework.web.bind.annotation.*;\nimport reactor.core.publisher.Mono;\n\nimport java.util.List;\n\n@RestController\n@RequiredArgsConstructor\n@RequestMapping("/${moduleName}/${requestName}")\npublic class ${className}Controller {\n\n    private final ${className}QueryService queryService;\n\n    private final ${className}CommandService commandService;\n\n    @PostMapping("/index")\n    public Mono<ApiResponse> index(@RequestBody @Valid ${className}PageQuery query) {\n        return ApiResponse.ok(queryService.index(query));\n    }\n\n    @PostMapping("/recycle")\n    public Mono<ApiResponse> recycle(@RequestBody @Valid ${className}PageQuery query) {\n        return ApiResponse.ok(queryService.recycle(query));\n    }\n\n    @PostMapping("/create")\n    public Mono<ApiResponse> create(@RequestBody @Valid ${className}Command command) {\n        return ApiResponse.ok(commandService.create(command));\n    }\n\n    @PutMapping("/update")\n    public Mono<ApiResponse> update(@RequestBody @Valid ${className}Command command) {\n        return ApiResponse.ok(commandService.update(command));\n    }\n\n    @PostMapping("/delete")\n    public Mono<ApiResponse> delete(@RequestParam("ids") List<Long> ids) {\n        return ApiResponse.ok(commandService.delete(ids));\n    }\n\n    @PostMapping("/restore")\n    public Mono<ApiResponse> restore(@RequestParam("ids") List<Long> ids) {\n        return ApiResponse.ok(commandService.restore(ids));\n    }\n\n    @DeleteMapping("/wipe")\n    public Mono<ApiResponse> wipe(@RequestParam("ids") List<Long> ids) {\n        return ApiResponse.ok(commandService.wipe(ids));\n    }\n}\n', `update_time` = NOW() WHERE `template_name` = 'controller';
UPDATE `gen_template` SET `template_content` = 'package ${packageName}.domain.${moduleName};\n\nimport reactor.core.publisher.Mono;\n\nimport java.util.List;\n\npublic interface Delete${className}DomainService {\n\n    Mono<Void> deleteByIds(List<Long> ids);\n\n}', `update_time` = NOW() WHERE `template_name` = 'deleteDomain';
UPDATE `gen_template` SET `template_content` = 'package ${packageName}.application.service.${moduleName};\n\nimport ${packageName}.domain.auth.ReactiveSecurityUtils;\nimport ${packageName}.domain.${moduleName}.*;\nimport lombok.RequiredArgsConstructor;\nimport org.springframework.stereotype.Component;\nimport reactor.core.publisher.Flux;\nimport reactor.core.publisher.Mono;\n\nimport java.util.List;\n\n@Component\n@RequiredArgsConstructor\npublic class Delete${className}DomainServiceImpl implements Delete${className}DomainService {\n\n    private final ${className}DomainRepository domainRepository;\n    <#assign idParams = []>\n    <#list aggregateViews as aggregateView>\n        <#if aggregateView.objectType == 1>\n            <#assign idParams += [aggregateView.objectName]>\n        </#if>\n    </#list>\n\n    @Override\n    public Mono<Void> deleteByIds(List<Long> ids) {\n        return Flux.fromIterable(ids)\n                .flatMap(id -> domainRepository.load(new ${idParams?join(", ")}(id))\n                        .flatMap(domain -> {\n                            domain.delete();\n                            return domainRepository.save(domain);\n                        }), ReactiveSecurityUtils.concurrency())\n                .then();\n    }\n}\n', `update_time` = NOW() WHERE `template_name` = 'deleteDomainImpl';
UPDATE `gen_template` SET `template_content` = 'package ${packageName}.domain.${moduleName};\n\nimport ${packageName}.domain.AbstractDomainMask;\nimport lombok.Data;\nimport lombok.EqualsAndHashCode;\n\n@EqualsAndHashCode(callSuper = true)\n@Data\npublic class ${className}Domain extends AbstractDomainMask {\n\n<#list aggregateViews as aggregateView>\n  <#if aggregateView.objectType != 4>\n    private ${aggregateView.objectName} ${aggregateView.objectName?uncap_first};\n\n  </#if>\n</#list>\n    public void create() {}\n\n            <#assign updateParamList = []>\n<#list aggregateViews as aggregateView>\n  <#if aggregateView.objectType != 4 && aggregateView.objectType != 1>\n            <#assign updateParamList += [aggregateView.objectName + " " + aggregateView.objectName?uncap_first]>\n  </#if>\n</#list>\n    public void update(${updateParamList?join(", ")}) {\n<#list aggregateViews as aggregateView>\n  <#if aggregateView.objectType != 4 && aggregateView.objectType != 1>\n        this.${aggregateView.objectName?uncap_first} = ${aggregateView.objectName?uncap_first};\n  </#if>\n</#list>\n    }\n\n    public void delete() {\n        super.setDeleteStatus(true);\n    }\n\n    public void restore() {\n        super.setDeleteStatus(false);\n    }\n}\n', `update_time` = NOW() WHERE `template_name` = 'domain';
UPDATE `gen_template` SET `template_content` = 'package ${packageName}.domain.${moduleName};\n\nimport ${packageName}.domain.DomainRepository;\n\n<#list aggregateViews as aggregateView>\n<#if aggregateView.objectType == 1>\npublic interface ${className}DomainRepository extends DomainRepository<${aggregateView.objectName}, ${className}Domain> {\n}\n</#if>\n</#list>', `update_time` = NOW() WHERE `template_name` = 'domainRepository';
UPDATE `gen_template` SET `template_content` = 'package ${packageName}.infrastructure.persistence;\n\nimport ${packageName}.domain.${moduleName}.*;\nimport ${packageName}.infrastructure.persistence.entity.${className}Entity;\nimport ${packageName}.infrastructure.persistence.r2dbc.${className}Repository;\nimport lombok.RequiredArgsConstructor;\nimport org.springframework.stereotype.Repository;\nimport reactor.core.publisher.Mono;\n\nimport java.util.Optional;\n\n@Repository\n@RequiredArgsConstructor\npublic class ${className}DomainRepositoryImpl implements ${className}DomainRepository {\n\n    private final ${className}Repository repository;\n    <#assign idParams = []>\n    <#list aggregateViews as aggregateView>\n        <#if aggregateView.objectType == 1>\n            <#assign idParams += [aggregateView.objectName + " " + aggregateView.objectName?uncap_first]>\n        </#if>\n    </#list>\n\n    @Override\n    public Mono<${className}Domain> load(${idParams?join(", ")}) {\n        return repository.findById(<#list aggregateViews as aggregateView><#if aggregateView.objectType == 1>${aggregateView.objectName?uncap_first}.value()<#break></#if></#list>).map(e -> {\n            ${className}Domain domain = new ${className}Domain();\n\n            <#list aggregateViews as aggregateView>\n                <#if aggregateView.objectType == 1>\n            domain.set${aggregateView.objectName}(new ${aggregateView.objectName}(e.getId()));\n                </#if>\n            </#list>\n\n            <#list aggregateViews as aggregateView>\n                <#if aggregateView.objectType != 1 && aggregateView.hasCreated>\n                    <#assign fieldList = aggregateView.objectValue?replace(\'"\', \'\')?replace(\'[\', \'\')?replace(\']\', \'\')?split(",")>\n                    <#assign constructorParams = []>\n                    <#list fieldList as field>\n                        <#assign fieldTrimmed = field?trim>\n                        <#list columnsViews as col>\n                            <#if col.propJavaEntity == fieldTrimmed>\n                                <#assign constructorParams += ["e.get" + fieldTrimmed?cap_first + "()"]>\n                            </#if>\n                        </#list>\n                    </#list>\n            domain.set${aggregateView.objectName}(new ${aggregateView.objectName}(${constructorParams?join(", ")}));\n                </#if>\n            </#list>\n\n            <#assign auditMap = {"createBy":"createBy", "createTime":"createTime", "updateBy":"updateBy", "updateTime":"updateTime", "version":"version", "deleteStatus":"deleteStatus", "create_by":"createBy", "create_time":"createTime", "update_by":"updateBy", "update_time":"updateTime", "delete_status":"deleteStatus"}>\n            <#list columnsViews as columnsView>\n                <#if auditMap[columnsView.propJavaEntity]??>\n            domain.set${auditMap[columnsView.propJavaEntity]?cap_first}(e.get${columnsView.propJavaEntity?cap_first}());\n                </#if>\n            </#list>\n\n            return domain;\n        });\n    }\n\n    @Override\n    public Mono<Long> save(${className}Domain domain) {\n        ${className}Entity entity = new ${className}Entity();\n\n        <#list aggregateViews as aggregateView>\n            <#if aggregateView.objectType == 1>\n                <#list columnsViews as columnsView>\n                    <#if columnsView.propColumnKey == "PRI">\n        entity.set${columnsView.propJavaEntity?cap_first}(Optional.ofNullable(domain.get${aggregateView.objectName}()).map(${aggregateView.objectName}::value).orElse(null));\n                    </#if>\n                </#list>\n            </#if>\n        </#list>\n\n        <#list aggregateViews as aggregateView>\n            <#if aggregateView.objectType != 1 && aggregateView.hasCreated>\n                <#assign fieldList = aggregateView.objectValue?replace(\'"\', \'\')?replace(\'[\', \'\')?replace(\']\', \'\')?split(",")>\n                <#list fieldList as field>\n                    <#assign fieldTrimmed = field?trim>\n                    <#list columnsViews as columnsView>\n                        <#if columnsView.propColumnKey != "PRI" && columnsView.propJavaEntity == fieldTrimmed>\n        entity.set${columnsView.propJavaEntity?cap_first}(domain.get${aggregateView.objectName}().${fieldTrimmed}());\n                        </#if>\n                    </#list>\n                </#list>\n            </#if>\n        </#list>\n\n        <#assign auditMap = {"createBy":"createBy", "createTime":"createTime", "updateBy":"updateBy", "updateTime":"updateTime", "version":"version", "deleteStatus":"deleteStatus", "create_by":"createBy", "create_time":"createTime", "update_by":"updateBy", "update_time":"updateTime", "delete_status":"deleteStatus"}>\n        <#list columnsViews as columnsView>\n            <#if auditMap[columnsView.propJavaEntity]??>\n        entity.set${columnsView.propJavaEntity?cap_first}(domain.get${auditMap[columnsView.propJavaEntity]?cap_first}());\n            </#if>\n        </#list>\n\n        return repository.save(entity).map(${className}Entity::getId);\n    }\n}\n', `update_time` = NOW() WHERE `template_name` = 'domainRepositoryImpl';
UPDATE `gen_template` SET `template_content` = 'package ${packageName}.infrastructure.persistence.entity;\n\nimport ${packageName}.domain.util.IdGenerate;\nimport lombok.Data;\nimport org.springframework.data.annotation.*;\nimport org.springframework.data.relational.core.mapping.Column;\nimport org.springframework.data.relational.core.mapping.Table;\n\n<#assign javaLangTypes = ["String", "Long", "Integer", "Boolean", "Double", "Float", "Short", "Byte", "Character"]>\n<#assign importPackages = {"LocalDateTime":"java.time", "LocalDate":"java.time", "LocalTime":"java.time", "Instant":"java.time", "ZonedDateTime":"java.time", "Duration":"java.time", "Period":"java.time", "BigDecimal":"java.math", "BigInteger":"java.math", "Date":"java.util", "Timestamp":"java.sql", "UUID":"java.util"}>\n<#assign imports = []>\n<#list columnsViews as property>\n  <#assign type = property.propJavaType>\n  <#if !(javaLangTypes?seq_contains(type)) && importPackages[type]?? && !(imports?seq_contains(type))>\n    <#assign imports += [type]>\n  </#if>\n</#list>\n<#assign importLines = []>\n<#list imports as imp>\n  <#assign importLines += ["${importPackages[imp]}.${imp}"]>\n</#list>\n<#list importLines?sort as importLine>\nimport ${importLine};\n</#list>\n\n@Data\n@Table("${tableName}")\npublic class ${className}Entity {\n\n<#list columnsViews as property>\n    <#if property.propJavaEntity == "deptId" || property.propJavaEntity == "dept_id">\n        <#continue>\n    </#if>\n    <#if property.propColumnKey == "PRI">\n    @Id\n    @IdGenerate\n    </#if>\n    <#if property.propJavaEntity == "createBy" || property.propJavaEntity == "create_by">\n    @CreatedBy\n    </#if>\n    <#if property.propJavaEntity == "createTime" || property.propJavaEntity == "create_time">\n    @CreatedDate\n    </#if>\n    <#if property.propJavaEntity == "updateBy" || property.propJavaEntity == "update_by">\n    @LastModifiedBy\n    </#if>\n    <#if property.propJavaEntity == "updateTime" || property.propJavaEntity == "update_time">\n    @LastModifiedDate\n    </#if>\n    <#if property.propJavaEntity == "version">\n    @Version\n    </#if>\n    @Column("${property.propColumnName}")\n    private ${property.propJavaType} ${property.propJavaEntity};\n\n</#list>\n}\n', `update_time` = NOW() WHERE `template_name` = 'entity';
UPDATE `gen_template` SET `template_content` = 'package ${packageName}.domain.${moduleName};\n\n<#assign javaLangTypes = ["String", "Long", "Integer", "Boolean", "Double", "Float", "Short", "Byte", "Character"]>\n<#assign importPackages = {"LocalDateTime":"java.time", "LocalDate":"java.time", "LocalTime":"java.time", "Instant":"java.time", "ZonedDateTime":"java.time", "Duration":"java.time", "Period":"java.time", "BigDecimal":"java.math", "BigInteger":"java.math", "Date":"java.util", "Timestamp":"java.sql", "UUID":"java.util"}>\n<#assign imports = []>\n<#list aggregateViews as aggregateView>\n<#if aggregateView.objectType == 3>\n<#assign fieldList = aggregateView.objectValue?replace(\'"\', \'\')?replace(\'[\', \'\')?replace(\']\', \'\')?split(",")>\n<#list fieldList as field>\n  <#assign fieldTrimmed = field?trim>\n  <#list columnsViews as col>\n    <#if col.propJavaEntity == fieldTrimmed>\n      <#assign type = col.propJavaType>\n      <#if !(javaLangTypes?seq_contains(type)) && importPackages[type]?? && !(imports?seq_contains(type))>\n        <#assign imports += [type]>\n      </#if>\n    </#if>\n  </#list>\n</#list>\n</#if>\n</#list>\n<#list imports as imp>\nimport ${importPackages[imp]}.${imp};\n</#list>\n\n<#list aggregateViews as aggregateView>\n<#if aggregateView.objectType == 3>\n<#assign fieldList = aggregateView.objectValue?replace(\'"\', \'\')?replace(\'[\', \'\')?replace(\']\', \'\')?split(",")>\n<#assign paramList = []>\n<#list fieldList as field>\n  <#assign fieldTrimmed = field?trim>\n  <#list columnsViews as col>\n    <#if col.propJavaEntity == fieldTrimmed>\n      <#assign paramList += [col.propJavaType + " " + fieldTrimmed]>\n    </#if>\n  </#list>\n</#list>\npublic record ${aggregateView.objectName}(${paramList?join(", ")}) {\n}\n</#if>\n</#list>\n', `update_time` = NOW() WHERE `template_name` = 'extendInfo';
