UPDATE `gen_template` SET `template_content` = 'package ${packageName}.application.service.${moduleName};\n\nimport ${packageName}.domain.${moduleName}.*;\nimport org.springframework.stereotype.Component;\n\n@Component\npublic class ${className}DomainFactoryImpl implements ${className}DomainFactory {\n<#assign updateParamList = []>\n<#list aggregateViews as aggregateView>\n  <#if aggregateView.objectType != 4 && aggregateView.objectType != 1>\n            <#assign updateParamList += [aggregateView.objectName + " " + aggregateView.objectName?uncap_first]>\n  </#if>\n</#list>\n\n    @Override\n    public ${className}Domain newInstance(${updateParamList?join(", ")}) {\n        ${className}Domain domain = new ${className}Domain();\n<#list aggregateViews as aggregateView>\n  <#if aggregateView.objectType != 4 && aggregateView.objectType != 1>\n        domain.set${aggregateView.objectName}(${aggregateView.objectName?uncap_first});\n  </#if>\n</#list>\n        return domain;\n    }\n}\n', `update_time` = NOW() WHERE `template_name` = 'factoryImpl';
UPDATE `gen_template` SET `template_content` = '<script lang="ts" setup>\nimport { ref } from \'vue\';\n\nimport { useVbenModal } from \'@vben/common-ui\';\nimport { $t } from \'@vben/locales\';\n\nimport { ElMessage } from \'element-plus\';\n\nimport { useVbenForm } from \'#/adapter/form\';\n<#assign filteredProperties = columnsViews?filter(p -> p.propDictId?exists && p.propDictId?has_content)>\n<#if filteredProperties?has_content>\nimport { getItemLabelByDictCode } from \'#/api/sys/dict\';\n</#if>\nimport { create${className}, update${className} } from \'#/api/${moduleName}/${requestName}\';\n\nconst props = defineProps<{\n  gridApi: any;\n}>();\n\nconst writeForm = ref<Record<string, any>>({});\n<#assign dateTimeFields = columnsViews?filter(p -> p.formComponentStr == \'DatePicker\' || p.formComponentStr == \'TimePicker\' || p.formComponentStr == \'DateTimePicker\')>\nconst dateTimeFields = new Set([<#list dateTimeFields as property>\'${property.propJavaEntity}\'<#sep>, </#sep></#list>]);\n\nconst [Form, formApi] = useVbenForm({\n  showDefaultActions: false,\n  layout: \'horizontal\',\n  commonConfig: {\n    componentProps: {\n      class: \'w-full\',\n    },\n    colon: true,\n    labelWidth: 150,\n  },\n  submitOnChange: true,\n  schema: [\n<#assign excludeFields = ["id", "createBy", "createTime", "updateBy", "updateTime", "version", "deptId", "dept_id", "deleteStatus", "create_by", "create_time", "update_by", "update_time", "delete_status"]>\n<#list columnsViews as property>\n<#if !excludeFields?seq_contains(property.propJavaEntity) && property.formVisible>\n<#if property.propDictId?exists && property.propDictId?has_content>\n    {\n      component: \'ApiSelect\',\n      componentProps: {\n        allowClear: true,\n        api: () => getItemLabelByDictCode(\'${property.propDictStr}\'),\n        labelField: \'itemLabel\',\n        valueField: \'itemValue\',\n        clearable: true,\n        placeholder: $t(\'${requestName}.${property.propJavaEntity}Placeholder\'),\n      },\n      fieldName: \'${property.propJavaEntity}\',\n      label: $t(\'${requestName}.${property.propJavaEntity}\'),\n<#if property.formRequired>\n      rules: \'required\',\n</#if>\n    },\n<#else>\n    {\n      component: \'${property.formComponentStr}\',\n      fieldName: \'${property.propJavaEntity}\',\n      label: $t(\'${requestName}.${property.propJavaEntity}\'),\n      componentProps: {\n        placeholder: $t(\'${requestName}.${property.propJavaEntity}Placeholder\'),\n      },\n<#if property.formRequired>\n      rules: \'required\',\n</#if>\n    },\n</#if>\n</#if>\n</#list>\n  ],\n});\n\nconst [Modal, modalApi] = useVbenModal({\n  onConfirm: () => {\n    formApi.validate().then(async (e) => {\n      if (e.valid) {\n        Object.assign(writeForm.value, await formApi.getValues());\n        await (writeForm.value.id\n          ? update${className}(writeForm.value)\n          : create${className}(writeForm.value));\n        ElMessage.success($t(\'system.common.save.success\'));\n        props.gridApi.reload();\n      } else {\n        ElMessage.error($t(\'system.common.validation.error\'));\n      }\n      await modalApi.setState({ loading: false }).close();\n    });\n  },\n  confirmText: $t(\'system.common.button.confirm\'),\n  cancelText: $t(\'system.common.button.cancel\'),\n});\n\nconst open = (row: any) => {\n  writeForm.value = {};\n  if (row?.id) {\n    const cleaned = { ...row };\n    dateTimeFields.forEach((field) => delete cleaned[field]);\n    writeForm.value = cleaned;\n    formApi.setValues(cleaned);\n  } else {\n    formApi.resetForm();\n  }\n  modalApi.open();\n};\nconst close = () => modalApi.close();\n\ndefineExpose({ open, close });\n</script>\n\n<template>\n  <Modal class="w-[40%]" :title="$t(\'system.common.alert.form\')">\n    <Form style="width: auto" />\n  </Modal>\n</template>\n', `update_time` = NOW() WHERE `template_name` = 'form.vue';
UPDATE `gen_template` SET `template_content` = '{\n<#assign excludeFields = ["createBy", "createTime", "updateBy", "updateTime", "version", "deptId", "dept_id", "deleteStatus", "create_by", "create_time", "update_by", "update_time", "delete_status"]>\n<#assign includedProps = []>\n<#list columnsViews as property>\n<#if !(excludeFields?seq_contains(property.propJavaEntity))>\n<#assign includedProps += [property]>\n</#if>\n</#list>\n  "title": "${className} Management"<#if includedProps?has_content>,\n<#list includedProps as prop>\n  "${prop.propJavaEntity}": "${prop.en}",\n  "${prop.propJavaEntity}Placeholder": "${(prop.propDictId?exists && prop.propDictId?has_content)?string(\'Please select\', \'Please enter\')} ${prop.en}"<#if prop_has_next>,</#if>\n</#list>\n</#if>\n}\n', `update_time` = NOW() WHERE `template_name` = 'i18n.en.json';
UPDATE `gen_template` SET `template_content` = '<#assign allLocaleNotEmpty = true>\n<#list columnsViews as item>\n  <#if !(item.locale?has_content)>\n    <#assign allLocaleNotEmpty = false>\n    <#break>\n  </#if>\n</#list>\n<#if allLocaleNotEmpty>\n{\n  <#assign excludeFields = ["createBy", "createTime", "updateBy", "updateTime", "version", "deptId", "dept_id", "deleteStatus", "create_by", "create_time", "update_by", "update_time", "delete_status"]>\n  <#assign includedProps = []>\n  <#list columnsViews as property>\n    <#if !(excludeFields?seq_contains(property.propJavaEntity))>\n      <#assign includedProps += [property]>\n    </#if>\n  </#list>\n  "title": "${className} Management"<#if includedProps?has_content>,\n  <#list includedProps as prop>\n  "${prop.propJavaEntity}": "${prop.locale}",\n  "${prop.propJavaEntity}Placeholder": "${(prop.propDictId?exists && prop.propDictId?has_content)?string(\'请选择\', \'请输入\')}${prop.locale}"<#if prop_has_next>,</#if>\n  </#list>\n</#if>\n}\n</#if>\n', `update_time` = NOW() WHERE `template_name` = 'i18n.locale.json';
UPDATE `gen_template` SET `template_content` = '<script lang="ts" setup>\n<#assign formFilteredProperties = columnsViews?filter(p -> p.tableFilter)>\n<#if formFilteredProperties?has_content>\nimport type { VbenFormProps } from \'#/adapter/form\';\n</#if>\nimport type { VxeTableGridOptions } from \'#/adapter/vxe-table\';\n\nimport { ref } from \'vue\';\n\nimport { useAccess } from \'@vben/access\';\nimport { confirm, Page } from \'@vben/common-ui\';\nimport { $t } from \'@vben/locales\';\n\nimport { ElButton, ElMessage } from \'element-plus\';\n\n<#assign dictFilteredProperties = columnsViews?filter(p -> p.propDictId?exists && p.propDictId?has_content)>\n<#if dictFilteredProperties?has_content>\nimport Dict from \'#/adapter/component/Dict.vue\';\n</#if>\nimport { useVbenVxeGrid } from \'#/adapter/vxe-table\';\n<#assign formDictFilteredProperties = formFilteredProperties?filter(p -> p.propDictId?exists && p.propDictId?has_content)>\n<#if formDictFilteredProperties?has_content>\nimport { getItemLabelByDictCode } from \'#/api/sys/dict\';\n</#if>\nimport { delete${className}, get${className}Page } from \'#/api/${moduleName}/${requestName}\';\n\nimport ${className}Form from \'./form.vue\';\nimport RecycleForm from \'./recycle.vue\';\n\nconst { hasAccessByCodes } = useAccess();\n\nconst ${requestName}FormRef = ref();\nconst recycleFormRef = ref();\n\ninterface RowType {\n<#assign excludeFields = ["createBy", "createTime", "updateBy", "updateTime", "version", "deptId", "dept_id", "deleteStatus", "create_by", "create_time", "update_by", "update_time", "delete_status"]>\n<#list columnsViews as property>\n    <#if !(excludeFields?seq_contains(property.propJavaEntity))>\n  ${property.propJavaEntity}: ${property.typescriptTypeStr};\n    </#if>\n</#list>\n}\n<#if formFilteredProperties?has_content>\nconst formOptions: VbenFormProps = {\n  collapsed: false,\n  schema: [\n    <#list formFilteredProperties as property>\n    {\n<#if property.propDictId?exists && property.propDictId?has_content>\n      component: \'ApiSelect\',\n      componentProps: {\n        allowClear: true,\n        api: () => getItemLabelByDictCode(\'${property.propDictStr}\'),\n        labelField: \'itemLabel\',\n        valueField: \'itemValue\',\n        clearable: true,\n        placeholder: $t(\'${requestName}.${property.propJavaEntity}Placeholder\'),\n      },\n<#else>\n      component: \'${property.tableFilterComponentStr}\',\n      componentProps: {\n        placeholder: $t(\'${requestName}.${property.propJavaEntity}Placeholder\'),\n<#if property.tableFilterComponentStr == \'DatePicker\'>\n        type: \'date\',\n        valueFormat: \'YYYY-MM-DD\',\n<#elseif property.tableFilterComponentStr == \'DateTimePicker\'>\n        type: \'datetime\',\n        valueFormat: \'YYYY-MM-DD HH:mm:ss\',\n<#elseif property.tableFilterComponentStr == \'TimePicker\'>\n        type: \'time\',\n        valueFormat: \'HH:mm:ss\',\n</#if>\n      },\n</#if>\n      fieldName: \'${property.propJavaEntity}\',\n      label: $t(\'${requestName}.${property.propJavaEntity}\'),\n    },\n    </#list>\n  ],\n  showCollapseButton: true,\n  submitButtonOptions: {\n    content: $t(\'system.common.button.search\'),\n  },\n  resetButtonOptions: {\n    content: $t(\'system.common.button.reset\'),\n  },\n  submitOnChange: false,\n  submitOnEnter: true,\n};\n</#if>\nconst gridOptions: VxeTableGridOptions<RowType> = {\n  checkboxConfig: {\n    highlight: true,\n  },\n  columnConfig: {\n    resizable: true,\n  },\n  rowConfig: {\n    isHover: true,\n  },\n  columns: [\n    { title: \'No.\', type: \'seq\', width: 50 },\n    { align: \'left\', title: \'#\', type: \'checkbox\', width: 50 },\n<#assign excludeFields = ["id", "createBy", "createTime", "updateBy", "updateTime", "version", "deptId", "dept_id", "deleteStatus", "create_by", "create_time", "update_by", "update_time", "delete_status"]>\n<#list columnsViews as property>\n    <#if !(excludeFields?seq_contains(property.propJavaEntity)) && property.tableVisible>\n    <#if property?has_content && property.propDictId?has_content>\n    {\n      field: \'${property.propJavaEntity}\',\n      title: $t(\'${requestName}.${property.propJavaEntity}\'),\n      slots: { default: \'${property.propJavaEntity}\' },\n<#if property.tableOrder>\n      sortable: true,\n</#if>\n    },\n    <#else>\n    {\n      field: \'${property.propJavaEntity}\',\n      title: $t(\'${requestName}.${property.propJavaEntity}\'),\n<#if property.tableOrder>\n      sortable: true,\n</#if>\n    },\n    </#if>\n    </#if>\n</#list>\n    {\n      field: \'action\',\n      fixed: \'right\',\n      slots: { default: \'action\' },\n      title: <#noparse>$t(\'system.common.operation\')</#noparse>,\n      width: 150,\n    },\n  ],\n  exportConfig: {},\n  keepSource: true,\n  proxyConfig: {\n    ajax: {\n<#if formFilteredProperties?has_content>\n      query: async ({ page }, formOptions) => {\n        return await get${className}Page({\n          pageNum: page.currentPage,\n          pageSize: page.pageSize,\n          ...formOptions,\n        });\n      },\n<#else>\n      query: async ({ page }) => {\n        return await get${className}Page({\n          pageNum: page.currentPage,\n          pageSize: page.pageSize,\n        });\n      },\n</#if>\n    },\n  },\n  editConfig: {\n    mode: \'row\',\n    trigger: \'click\',\n  },\n  toolbarConfig: {\n    custom: true,\n    export: true,\n    // import: true,\n    refresh: true,\n    zoom: true,\n<#if formFilteredProperties?has_content>\n    search: true,\n<#else>\n    search: false,\n</#if>\n  },\n};\n\nconst [Grid, gridApi] = useVbenVxeGrid({\n  gridOptions,\n<#if formFilteredProperties?has_content>\n  formOptions,\n</#if>\n});\n\nconst openRecycleForm = () => {\n  recycleFormRef.value?.open();\n};\n\nconst openForm = () => {\n  ${requestName}FormRef.value?.open();\n};\n\nconst editRow = (row: RowType) => {\n  ${requestName}FormRef.value?.open(row);\n};\n\nconst deleteMethod = (row?: RowType) => {\n  const ids = row\n    ? [row.id]\n    : gridApi.grid.getCheckboxRecords().map((item) => item.id);\n\n  if (ids.length === 0) {\n    ElMessage.warning(<#noparse>$t(\'system.common.delete.warning\')</#noparse>);\n    return;\n  }\n\n  confirm({\n    content: <#noparse>$t(\'system.common.delete.confirm\')</#noparse>,\n    icon: \'error\',\n  }).then(async () => {\n    try {\n      await delete${className}(ids);\n      await gridApi.reload();\n      ElMessage.success(<#noparse>$t(\'system.common.delete.success\')</#noparse>);\n    } catch {\n      ElMessage.error(<#noparse>$t(\'system.common.delete.error\')</#noparse>);\n    }\n  });\n};\n</script>\n\n<template>\n  <Page>\n    <Grid>\n<#if dictFilteredProperties?has_content>\n<#list columnsViews as property>\n<#if property?has_content && property.propDictId?has_content>\n      <template #${property.propJavaEntity}="{ row }">\n        <Dict dict-key="${property.propDictStr}" :value="row.${property.propJavaEntity}" />\n      </template>\n</#if>\n</#list>\n</#if>\n      <template #toolbar-actions>\n        <ElButton\n          class="mr-2"\n          bg\n          text\n          type="primary"\n          @click="openForm"\n          v-if="hasAccessByCodes([\'${moduleName}:${requestName}:create\'])"\n        >\n          {{ <#noparse>$t(\'system.common.button.add\')</#noparse> }}\n        </ElButton>\n        <ElButton\n          class="mr-2"\n          bg\n          text\n          type="danger"\n          @click="deleteMethod()"\n          v-if="hasAccessByCodes([\'${moduleName}:${requestName}:delete\'])"\n        >\n          {{ <#noparse>$t(\'system.common.button.delete\')</#noparse> }}\n        </ElButton>\n        <ElButton\n          class="mr-2"\n          bg\n          text\n          type="info"\n          @click="openRecycleForm"\n          v-if="hasAccessByCodes([\'${moduleName}:${requestName}:recycle\'])"\n        >\n          {{ <#noparse>$t(\'system.common.button.recycle\')</#noparse> }}\n        </ElButton>\n      </template>\n      <template #action="{ row }">\n        <ElButton\n          type="primary"\n          link\n          @click="editRow(row)"\n          v-if="hasAccessByCodes([\'${moduleName}:${requestName}:update\'])"\n        >\n          {{ <#noparse>$t(\'system.common.button.edit\')</#noparse> }}\n        </ElButton>\n        <ElButton\n          type="danger"\n          link\n          @click="deleteMethod(row)"\n          v-if="hasAccessByCodes([\'${moduleName}:${requestName}:delete\'])"\n        >\n          {{ <#noparse>$t(\'system.common.button.delete\')</#noparse> }}\n        </ElButton>\n      </template>\n    </Grid>\n    <${className}Form ref="${requestName}FormRef" :grid-api="gridApi" />\n    <RecycleForm ref="recycleFormRef" :grid-api="gridApi" />\n  </Page>\n</template>\n', `update_time` = NOW() WHERE `template_name` = 'index.vue';
UPDATE `gen_template` SET `template_content` = 'package ${packageName}.application.service.${moduleName}.dto;\n\nimport ${packageName}.infrastructure.persistence.entity.${className}Entity;\nimport org.mapstruct.Mapper;\n\nimport java.util.List;\n\n@Mapper(componentModel = "spring")\npublic interface ${className}ViewMapStruct {\n\n    ${className}View toView(${className}Entity entity);\n\n    List<${className}View<#noparse>></#noparse> toViews(List<${className}Entity<#noparse>></#noparse> entities);\n}\n', `update_time` = NOW() WHERE `template_name` = 'mapstruct';
