pdate_time` = NOW() WHERE `template_name` = 'objectValue';
UPDATE `gen_template` SET `template_content` = 'package ${packageName}.application.service.${moduleName}.dto;\n\nimport jakarta.validation.constraints.NotNull;\nimport lombok.Data;\nimport lombok.EqualsAndHashCode;\n\nimport java.io.Serializable;\n\n@EqualsAndHashCode(callSuper = true)\n@Data\npublic class ${className}PageQuery extends ${className}Query implements Serializable {\n\n    @NotNull(message = "pageNum不能为空")\n    private Integer pageNum;\n\n    @NotNull(message = "pageSize不能为空")\n    private Integer pageSize;\n}\n', `update_time` = NOW() WHERE `template_name` = 'pageQuery';
UPDATE `gen_template` SET `template_content` = 'package ${packageName}.application.service.${moduleName}.dto;\n\nimport lombok.Data;\nimport lombok.experimental.FieldNameConstants;\nimport java.io.Serializable;\n<#assign javaLangTypes = ["String", "Long", "Integer", "Boolean", "Double", "Float", "Short", "Byte", "Character"]>\n<#assign importPackages = {"LocalDateTime":"java.time", "LocalDate":"java.time", "LocalTime":"java.time", "Instant":"java.time", "ZonedDateTime":"java.time", "Duration":"java.time", "Period":"java.time", "BigDecimal":"java.math", "BigInteger":"java.math", "Date":"java.util", "Timestamp":"java.sql", "UUID":"java.util"}>\n<#assign imports = []>\n<#list columnsViews as property>\n    <#if !(["createBy", "createTime", "updateBy", "updateTime", "version", "deptId", "dept_id", "create_by", "create_time", "update_by", "update_time"]?seq_contains(property.propJavaEntity))>\n      <#assign type = property.propJavaType>\n      <#if !(javaLangTypes?seq_contains(type)) && importPackages[type]?? && !(imports?seq_contains(type))>\n        <#assign imports += [type]>\n      </#if>\n    </#if>\n</#list>\n<#list imports as imp>\nimport ${importPackages[imp]}.${imp};\n</#list>\n\n@Data\n@FieldNameConstants\npublic class ${className}Query implements Serializable {\n    <#assign excludeFields = ["createBy", "createTime", "updateBy", "updateTime", "version", "deptId", "dept_id", "create_by", "create_time", "update_by", "update_time"]>\n\n    <#list columnsViews as property>\n        <#if !(excludeFields?seq_contains(property.propJavaEntity))>\n    private ${property.propJavaType} ${property.propJavaEntity};\n\n        </#if>\n    </#list>\n}\n', `update_time` = NOW() WHERE `template_name` = 'query';
UPDATE `gen_template` SET `template_content` = 'package ${packageName}.application.service.${moduleName};\n\nimport ${packageName}.application.service.${moduleName}.dto.*;\nimport ${packageName}.domain.util.PageResponse;\nimport ${packageName}.infrastructure.persistence.entity.${className}Entity;\nimport lombok.RequiredArgsConstructor;\nimport org.springframework.data.r2dbc.core.R2dbcEntityTemplate;\nimport org.springframework.data.relational.core.query.Criteria;\nimport org.springframework.data.relational.core.query.Query;\nimport org.springframework.stereotype.Service;\nimport reactor.core.publisher.Mono;\n\nimport java.util.List;\n\n@Service\n@RequiredArgsConstructor\npublic class ${className}QueryService {\n\n    private final R2dbcEntityTemplate r2dbcEntityTemplate;\n\n    private final ${className}ViewMapStruct mapStruct;\n\n    public Mono<PageResponse<${className}View>> index(${className}PageQuery query) {\n<#assign criteriaGenerated = false>\n<#list columnsViews as columnsView>\n    <#assign fields = ["deleteStatus", "delete_status"]>\n    <#list fields as field>\n        <#if columnsView.propJavaEntity == field && !criteriaGenerated>\n        Criteria criteria = Criteria.where("delete_status").is(false);\n            <#assign criteriaGenerated = true>\n        </#if>\n    </#list>\n</#list>\n<#if !criteriaGenerated>\n        Criteria criteria = Criteria.empty();\n</#if>\n<#assign queryExcludeFields = ["id", "createBy", "createTime", "updateBy", "updateTime", "version", "deleteStatus", "create_by", "create_time", "update_by", "update_time", "delete_status"]>\n<#list columnsViews as columnsView>\n    <#if !(queryExcludeFields?seq_contains(columnsView.propJavaEntity))>\n        <#if columnsView.propJavaType == "String">\n        if (query.get${columnsView.propJavaEntity?cap_first}() != null && !query.get${columnsView.propJavaEntity?cap_first}().isEmpty()) {\n        <#else>\n        if (query.get${columnsView.propJavaEntity?cap_first}() != null) {\n        </#if>\n            criteria = criteria.and(Criteria.where("${columnsView.propColumnName}")<#if columnsView.tableFilterTypeStr?? && columnsView.tableFilterTypeStr == "like">.like("%" + query.get${columnsView.propJavaEntity?cap_first}() + "%")<#elseif columnsView.tableFilterTypeStr?? && columnsView.tableFilterTypeStr == "<">.lessThan(query.get${columnsView.propJavaEntity?cap_first}())<#elseif columnsView.tableFilterTypeStr?? && columnsView.tableFilterTypeStr == ">">.greaterThan(query.get${columnsView.propJavaEntity?cap_first}())<#elseif columnsView.tableFilterTypeStr?? && columnsView.tableFilterTypeStr == "<=">.lessThanOrEquals(query.get${columnsView.propJavaEntity?cap_first}())<#elseif columnsView.tableFilterTypeStr?? && columnsView.tableFilterTypeStr == ">=">.greaterThanOrEquals(query.get${columnsView.propJavaEntity?cap_first}())<#elseif columnsView.tableFilterTypeStr?? && columnsView.tableFilterTypeStr == "!=" >.not(query.get${columnsView.propJavaEntity?cap_first}())<#else>.is(query.get${columnsView.propJavaEntity?cap_first}())</#if>);\n        }\n    </#if>\n</#list>\n        Query qry = Query.query(criteria)\n                .limit(query.getPageSize())\n                .offset((long) (query.getPageNum() - 1) * query.getPageSize());\n        Mono<List<${className}View>> list = r2dbcEntityTemplate.select(${className}Entity.class).matching(qry).all().collectList().map(mapStruct::toViews);\n        Mono<Long> count = r2dbcEntityTemplate.count(Query.query(criteria), ${className}Entity.class);\n        return Mono.zip(list, count).map(tuple -> new PageResponse<>(tuple.getT1(), tuple.getT2(), query.getPageNum(), query.getPageSize()));\n    }\n\n    public Mono<PageResponse<${className}View>> recycle(${className}PageQuery query) {\n<#assign criteriaGenerated = false>\n<#list columnsViews as columnsView>\n    <#assign fields = ["deleteStatus", "delete_status"]>\n    <#list fields as field>\n        <#if columnsView.propJavaEntity == field && !criteriaGenerated>\n        Criteria criteria = Criteria.where("delete_status").is(true);\n            <#assign criteriaGenerated = true>\n        </#if>\n    </#list>\n</#list>\n<#if !criteriaGenerated>\n        Criteria criteria = Criteria.empty();\n</#if>\n<#assign queryExcludeFields = ["id", "createBy", "createTime", "updateBy", "updateTime", "version", "deleteStatus", "create_by", "create_time", "update_by", "update_time", "delete_status"]>\n<#list columnsViews as columnsView>\n    <#if !(queryExcludeFields?seq_contains(columnsView.propJavaEntity))>\n        <#if columnsView.propJavaType == "String">\n        if (query.get${columnsView.propJavaEntity?cap_first}() != null && !query.get${columnsView.propJavaEntity?cap_first}().isEmpty()) {\n        <#else>\n        if (query.get${columnsView.propJavaEntity?cap_first}() != null) {\n        </#if>\n            criteria = criteria.and(Criteria.where("${columnsView.propColumnName}")<#if columnsView.tableFilterTypeStr?? && columnsView.tableFilterTypeStr == "like">.like("%" + query.get${columnsView.propJavaEntity?cap_first}() + "%")<#elseif columnsView.tableFilterTypeStr?? && columnsView.tableFilterTypeStr == "<">.lessThan(query.get${columnsView.propJavaEntity?cap_first}())<#elseif columnsView.tableFilterTypeStr?? && columnsView.tableFilterTypeStr == ">">.greaterThan(query.get${columnsView.propJavaEntity?cap_first}())<#elseif columnsView.tableFilterTypeStr?? && columnsView.tableFilterTypeStr == "<=">.lessThanOrEquals(query.get${columnsView.propJavaEntity?cap_first}())<#elseif columnsView.tableFilterTypeStr?? && columnsView.tableFilterTypeStr == ">=">.greaterThanOrEquals(query.get${columnsView.propJavaEntity?cap_first}())<#elseif columnsView.tableFilterTypeStr?? && columnsView.tableFilterTypeStr == "!=" >.not(query.get${columnsView.propJavaEntity?cap_first}())<#else>.is(query.get${columnsView.propJavaEntity?cap_first}())</#if>);\n        }\n    </#if>\n</#list>\n        Query qry = Query.query(criteria)\n                .limit(query.getPageSize())\n                .offset((long) (query.getPageNum() - 1) * query.getPageSize());\n        Mono<List<${className}View>> list = r2dbcEntityTemplate.select(${className}Entity.class).matching(qry).all().collectList().map(mapStruct::toViews);\n        Mono<Long> count = r2dbcEntityTemplate.count(Query.query(criteria), ${className}Entity.class);\n        return Mono.zip(list, count).map(tuple -> new PageResponse<>(tuple.getT1(), tuple.getT2(), query.getPageNum(), query.getPageSize()));\n    }\n}\n', `update_time` = NOW() WHERE `template_name` = 'queryService';
UPDATE `gen_template` SET `template_content` = 'package ${packageName}.infrastructure.persistence.r2dbc;\n\nimport ${packageName}.infrastructure.persistence.entity.${className}Entity;\nimport org.springframework.data.repository.reactive.ReactiveCrudRepository;\n\npublic interface ${className}Repository extends ReactiveCrudRepository<${className}Entity, Long>{\n}\n', `update_time` = NOW() WHERE `template_name` = 'r2dbc';
UPDATE `gen_template` SET `template_content` = '============ CN ================\n\n1. 将 README 目录下的 SQL.sql 放入到你的数据库中执行。\n\n2. 将如下 ts 追加到 apps/web-ele/src/api/${moduleName} 目录下（如果该目录下没有 index.ts 则手动创建一个，再追加进去）:\nexport * from \'./${requestName}/\';\n\n3. 将如下 ts 追加到 apps/web-ele/src/api/index.ts（只需要追加菜单目录名）:\nexport * from \'./${moduleName}\';\n\n============ EN ================\n\n1. Drop the `SQL.sql` from the README folder into your database and run it.\n\n2. Add this TS snippet to `apps/web‑ele/src/api/${moduleName}` – if there’s no `index.ts` in that folder, create one first and then append:  \n   export * from \'./${requestName}/\';\n\n3. Append the following line to `apps/web‑ele/src/api/index.ts` (just the menu‑folder name):  \n   export * from \'./${moduleName}\';', `update_time` = NOW() WHERE `template_name` = 'readme.txt';
UPDATE `gen_template` SET `template_content` = '<script lang="ts" setup>\nimport type { VxeTableGridOptions } from \'#/adapter/vxe-table\';\n\nimport { useAccess } from \'@vben/access\';\nimport { confirm, useVbenModal } from \'@vben/common-ui\';\nimport { $t } from \'@vben/locales\';\n\nimport { ElButton, ElMessage } from \'element-plus\';\n\n<#assign dictFilteredProperties = columnsViews?filter(p -> p.propDictId?exists && p.propDictId?has_content)>\n<#if dictFilteredProperties?has_content>\nimport Dict from \'#/adapter/component/Dict.vue\';\n</#if>\nimport { useVbenVxeGrid } from \'#/adapter/vxe-table\';\nimport {\n  get${className}RecyclePage,\n  restore${className},\n  wipe${className},\n} from \'#/api/${moduleName}/${requestName}\';\n\nconst props = defineProps<{\n  gridApi: any;\n}>();\n\nconst [Modal, modalApi] = useVbenModal({});\n\nconst open = () => {\n  modalApi.open();\n};\nconst close = () => {\n  modalApi.close();\n};\n\ndefineExpose({ open, close });\n\nconst { hasAccessByCodes } = useAccess();\n\ninterface RowType {\n<#assign excludeFields = ["createBy", "createTime", "updateBy", "updateTime", "version", "deptId", "dept_id", "deleteStatus", "create_by", "create_time", "update_by", "update_time", "delete_status"]>\n<#list columnsViews as property>\n    <#if !(excludeFields?seq_contains(property.propJavaEntity))>\n  ${property.propJavaEntity}: ${property.typescriptTypeStr};\n    </#if>\n</#list>\n}\n\nconst gridOptions: VxeTableGridOptions<RowType> = {\n  checkboxConfig: {\n    highlight: true,\n  },\n  columnConfig: {\n    resizable: true,\n  },\n  rowConfig: {\n    isHover: true,\n  },\n  columns: [\n    { title: \'No.\', type: \'seq\', width: 50 },\n    { align: \'left\', title: \'#\', type: \'checkbox\', width: 50 },\n<#assign excludeFields = ["id", "createBy", "createTime", "updateBy", "updateTime", "version", "deptId", "dept_id", "deleteStatus", "create_by", "create_time", "update_by", "update_time", "delete_status"]>\n<#list columnsViews as property>\n    <#if !(excludeFields?seq_contains(property.propJavaEntity)) && property.tableVisible>\n    <#if property?has_content && property.propDictId?has_content>\n    {\n      field: \'${property.propJavaEntity}\',\n      title: $t(\'${requestName}.${property.propJavaEntity}\'),\n      slots: { default: \'${property.propJavaEntity}\' },\n<#if property.tableOrder>\n      sortable: true,\n</#if>\n    },\n    <#else>\n    {\n      field: \'${property.propJavaEntity}\',\n      title: $t(\'${requestName}.${property.propJavaEntity}\'),\n<#if property.tableOrder>\n      sortable: true,\n</#if>\n    },\n    </#if>\n    </#if>\n</#list>\n    {\n      field: \'action\',\n      fixed: \'right\',\n      slots: { default: \'action\' },\n      title: $t(\'system.common.operation\'),\n      width: 150,\n    },\n  ],\n  exportConfig: {},\n  keepSource: true,\n  proxyConfig: {\n    ajax: {\n      query: async ({ page }) => {\n        return await get${className}RecyclePage({\n          pageNum: page.currentPage,\n          pageSize: page.pageSize,\n        });\n      },\n    },\n  },\n  editConfig: {\n    mode: \'row\',\n    trigger: \'click\',\n  },\n  toolbarConfig: {\n    custom: true,\n    export: true,\n    // import: true,\n    refresh: true,\n    zoom: true,\n    search: false,\n  },\n};\n\nconst [Grid, localGridApi] = useVbenVxeGrid({\n  gridOptions,\n});\n\nconst wipeMethod = (row?: RowType) => {\n  const ids = row\n    ? [row.id]\n    : localGridApi.grid.getCheckboxRecords().map((item) => item.id);\n\n  if (ids.length === 0) {\n    ElMessage.warning($t(\'system.common.delete.warning\'));\n    return;\n  }\n\n  confirm({\n    content: $t(\'system.common.delete.confirm\'),\n    icon: \'error\',\n  }).then(async () => {\n    await wipe${className}(ids)\n      .then(async () => {\n        await localGridApi.reload();\n        ElMessage.success($t(\'system.common.delete.success\'));\n        await props.gridApi.reload();\n      })\n      .catch(() => {\n        ElMessage.error($t(\'system.common.delete.error\'));\n      });\n  });\n};\n\nconst restoreMethod = (row?: RowType) => {\n  const ids = row\n    ? [row.id]\n    : localGridApi.grid.getCheckboxRecords().map((item) => item.id);\n\n  if (ids.length === 0) {\n    ElMessage.warning($t(\'system.common.restore.warning\'));\n    return;\n  }\n\n  confirm({\n    content: $t(\'system.common.restore.confirm\'),\n    icon: \'error\',\n  }).then(async () => {\n    try {\n      await restore${className}(ids);\n      await localGridApi.reload();\n      await props.gridApi.reload();\n      ElMessage.success($t(\'system.common.restore.success\'));\n    } catch {\n      ElMessage.error($t(\'system.common.restore.error\'));\n    }\n  });\n};\n</script>\n\n<template>\n  <Modal class="w-[80%]" :title="$t(\'system.common.button.recycle\')">\n    <Grid>\n<#if dictFilteredProperties?has_content>\n<#list columnsViews as property>\n<#if property?has_content && property.propDictId?has_content>\n      <template #${property.propJavaEntity}="{ row }">\n        <Dict dict-key="${property.propDictStr}" :value="row.${property.propJavaEntity}" />\n      </template>\n</#if>\n</#list>\n</#if>\n      <template #toolbar-actions>\n        <ElButton\n          class="mr-2"\n          bg\n          text\n          type="primary"\n          @click="restoreMethod()"\n          v-if="hasAccessByCodes([\'${moduleName}:${requestName}:restore\'])"\n        >\n          {{ $t(\'system.common.button.restore\') }}\n        </ElButton>\n        <ElButton\n          class="mr-2"\n          bg\n          text\n          type="danger"\n          @click="wipeMethod()"\n          v-if="hasAccessByCodes([\'${moduleName}:${requestName}:wipe\'])"\n        >\n          {{ $t(\'system.common.button.delete\') }}\n        </ElButton>\n      </template>\n      <template #action="{ row }">\n        <ElButton\n          type="success"\n          link\n          @click="restoreMethod(row)"\n          v-if="hasAccessByCodes([\'${moduleName}:${requestName}:restore\'])"\n        >\n          {{ $t(\'system.common.button.restore\') }}\n        </ElButton>\n        <ElButton\n          type="danger"\n          link\n          @click="wipeMethod(row)"\n          v-if="hasAccessByCodes([\'${moduleName}:${requestName}:wipe\'])"\n        >\n          {{ $t(\'system.common.button.wipe\') }}\n        </ElButton>\n      </template>\n    </Grid>\n  </Modal>\n</template>\n', `update_time` = NOW() WHERE `template_name` = 'recycle.vue';
UPDATE `gen_template` SET `template_content` = 'package ${packageName}.domain.${moduleName};\n\nimport reactor.core.publisher.Mono;\n\nimport java.util.List;\n\npublic interface Restore${className}DomainService {\n\n    Mono<Void> restoreByIds(List<Long> ids);\n\n}\n', `update_time` = NOW() WHERE `template_name` = 'restoreDomain';
UPDATE `gen_template` SET `template_content` = 'package ${packageName}.application.service.${moduleName};\n\nimport ${packageName}.domain.auth.ReactiveSecurityUtils;\nimport ${packageName}.domain.${moduleName}.*;\nimport lombok.RequiredArgsConstructor;\nimport org.springframework.stereotype.Component;\nimport reactor.core.publisher.Flux;\nimport reactor.core.publisher.Mono;\n\nimport java.util.List;\n\n@Component\n@RequiredArgsConstructor\npublic class Restore${className}DomainServiceImpl implements Restore${className}DomainService {\n\n    private final ${className}DomainRepository domainRepository;\n    <#assign idParams = []>\n    <#list aggregateViews as aggregateView>\n        <#if aggregateView.objectType == 1>\n            <#assign idParams += [aggregateView.objectName]>\n        </#if>\n    </#list>\n\n    @Override\n    public Mono<Void> restoreByIds(List<Long> ids) {\n        return Flux.fromIterable(ids)\n                .flatMap(id -> domainRepository.load(new ${idParams?join(", ")}(id))\n                        .flatMap(domain -> {\n                            domain.restore();\n                            return domainRepository.save(domain);\n                        }), ReactiveSecurityUtils.concurrency())\n                .then();\n    }\n}\n', `update_time` = NOW() WHERE `template_name` = 'restoreDomainImpl';
UPDATE `gen_template` SET `template_content` = '<#assign roleId = roleId!1750159408244>\n-- 自动生成的菜单权限 SQL\n-- module: ${moduleName}, requestName: ${requestName}\n\n-- 0. 清理该 requestName 已存在的旧菜单及权限绑定（避免同模块下多个 requestName 互相覆盖）\nDELETE rm FROM `sys_role_menu` rm INNER JOIN `sys_menu` m ON rm.`menu_id` = m.`id`\nWHERE m.`path` = \'/${moduleName}/${requestName}\'\n   OR m.`permission` LIKE \'${moduleName}:${requestName}:%\'\n   OR m.`component` LIKE \'/${moduleName}/${requestName}/%\';\nDELETE FROM `sys_menu`\nWHERE `path` = \'/${moduleName}/${requestName}\'\n   OR `permission` LIKE \'${moduleName}:${requestName}:%\'\n   OR `component` LIKE \'/${moduleName}/${requestName}/%\';\n\n-- 1. module 目录菜单（已存在则忽略，避免同模块多个 requestName 冲突）\nINSERT IGNORE INTO `sys_menu` (\n  `id`, `parent_id`, `name`, `path`, `component`, `api`, `permission`,\n  `sort_order`, `title`, `icon`, `menu_type`,\n  `visible`, `menu_status`, `create_by`, `update_by`,\n  `create_time`, `update_time`, `delete_status`, `version`, `depth`, `tree_path`\n) VALUES (\n  ${dirId?c}, NULL, \'${requestName?cap_first} Management\', \'/${moduleName}\', NULL, NULL, NULL,\n  1, \'${requestName}.title\', \'ant-design:folder-outlined\', 1,\n  1, 1, \'admin\', \'admin\', NOW(), NOW(), 0, 0, 0, \'/${dirId?c}/\'\n);\n\n-- 1b. 若该目录此前被软删除或缺少 depth/tree_path，恢复并补全，避免新菜单挂在不可见父目录下或无法进入权限树\nUPDATE `sys_menu` SET `delete_status` = 0, `visible` = 1, `menu_status` = 1, `depth` = 0, `tree_path` = CONCAT(\'/\', `id`, \'/\')\nWHERE `path` = \'/${moduleName}\' AND `menu_type` = 1;\n\nSET @dir_id = (SELECT `id` FROM `sys_menu` WHERE `path` = \'/${moduleName}\' LIMIT 1);\n\n-- 2. 列表页菜单\nSET @menu_id = ${menuId?c};\nINSERT INTO `sys_menu` (\n  `id`, `parent_id`, `name`, `path`, `component`, `api`, `permission`,\n  `sort_order`, `title`, `menu_type`,\n  `visible`, `menu_status`, `create_by`, `update_by`,\n  `create_time`, `update_time`, `delete_status`, `version`, `depth`, `tree_path`\n) VALUES (\n  ${menuId?c}, @dir_id, \'${requestName?cap_first} List\', \'/${moduleName}/${requestName}\', \'/${moduleName}/${requestName}/index\', NULL, NULL,\n  1, \'${requestName}.title\', 2,\n  1, 1, \'admin\', \'admin\', NOW(), NOW(), 0, 0, 1, CONCAT(\'/\', @dir_id, \'/\', ${menuId?c}, \'/\')\n);\n\n-- 3. 按钮权限\nINSERT INTO `sys_menu` (\n  `id`, `parent_id`, `name`, `component`, `api`, `permission`,\n  `sort_order`, `menu_type`, `visible`, `menu_status`,\n  `create_by`, `update_by`, `create_time`, `update_time`, `delete_status`, `version`, `depth`, `tree_path`\n) VALUES\n(${btnIndexId?c},   @menu_id, \'Index\',   NULL, \'/${moduleName}/${requestName}/index\',   \'${moduleName}:${requestName}:index\',   1, 3, 1, 1, \'admin\', \'admin\', NOW(), NOW(), 0, 0, 2, CONCAT(\'/\', @dir_id, \'/\', ${menuId?c}, \'/\', ${btnIndexId?c}, \'/\')),\n(${btnRecycleId?c}, @menu_id, \'Recycle\', NULL, \'/${moduleName}/${requestName}/recycle\', \'${moduleName}:${requestName}:recycle\', 2, 3, 1, 1, \'admin\', \'admin\', NOW(), NOW(), 0, 0, 2, CONCAT(\'/\', @dir_id, \'/\', ${menuId?c}, \'/\', ${btnRecycleId?c}, \'/\')),\n(${btnCreateId?c},  @menu_id, \'Create\',  NULL, \'/${moduleName}/${requestName}/create\',  \'${moduleName}:${requestName}:create\',  3, 3, 1, 1, \'admin\', \'admin\', NOW(), NOW(), 0, 0, 2, CONCAT(\'/\', @dir_id, \'/\', ${menuId?c}, \'/\', ${btnCreateId?c}, \'/\')),\n(${btnUpdateId?c},  @menu_id, \'Update\',  NULL, \'/${moduleName}/${requestName}/update\',  \'${moduleName}:${requestName}:update\',  4, 3, 1, 1, \'admin\', \'admin\', NOW(), NOW(), 0, 0, 2, CONCAT(\'/\', @dir_id, \'/\', ${menuId?c}, \'/\', ${btnUpdateId?c}, \'/\')),\n(${btnDeleteId?c},  @menu_id, \'Delete\',  NULL, \'/${moduleName}/${requestName}/delete\',  \'${moduleName}:${requestName}:delete\',  5, 3, 1, 1, \'admin\', \'admin\', NOW(), NOW(), 0, 0, 2, CONCAT(\'/\', @dir_id, \'/\', ${menuId?c}, \'/\', ${btnDeleteId?c}, \'/\')),\n(${btnRestoreId?c}, @menu_id, \'Restore\', NULL, \'/${moduleName}/${requestName}/restore\', \'${moduleName}:${requestName}:restore\', 6, 3, 1, 1, \'admin\', \'admin\', NOW(), NOW(), 0, 0, 2, CONCAT(\'/\', @dir_id, \'/\', ${menuId?c}, \'/\', ${btnRestoreId?c}, \'/\')),\n(${btnWipeId?c},    @menu_id, \'Wipe\',    NULL, \'/${moduleName}/${requestName}/wipe\',    \'${moduleName}:${requestName}:wipe\',    7, 3, 1, 1, \'admin\', \'admin\', NOW(), NOW(), 0, 0, 2, CONCAT(\'/\', @dir_id, \'/\', ${menuId?c}, \'/\', ${btnWipeId?c}, \'/\'));\n\n-- 4. 绑定到 ADMIN 角色\nINSERT INTO `sys_role_menu` (`id`, `role_id`, `menu_id`, `create_by`, `update_by`, `create_time`, `update_time`, `delete_status`) VALUES\n(${rmDirId?c},        ${roleId?c}, @dir_id,        \'admin\', \'admin\', NOW(), NOW(), 0),\n(${rmMenuId?c},       ${roleId?c}, @menu_id,       \'admin\', \'admin\', NOW(), NOW(), 0),\n(${rmBtnIndexId?c},   ${roleId?c}, ${btnIndexId?c},   \'admin\', \'admin\', NOW(), NOW(), 0),\n(${rmBtnRecycleId?c}, ${roleId?c}, ${btnRecycleId?c}, \'admin\', \'admin\', NOW(), NOW(), 0),\n(${rmBtnCreateId?c},  ${roleId?c}, ${btnCreateId?c},  \'admin\', \'admin\', NOW(), NOW(), 0),\n(${rmBtnUpdateId?c},  ${roleId?c}, ${btnUpdateId?c},  \'admin\', \'admin\', NOW(), NOW(), 0),\n(${rmBtnDeleteId?c},  ${roleId?c}, ${btnDeleteId?c},  \'admin\', \'admin\', NOW(), NOW(), 0),\n(${rmBtnRestoreId?c}, ${roleId?c}, ${btnRestoreId?c}, \'admin\', \'admin\', NOW(), NOW(), 0),\n(${rmBtnWipeId?c},    ${roleId?c}, ${btnWipeId?c},    \'admin\', \'admin\', NOW(), NOW(), 0);\n', `update_time` = NOW() WHERE `template_name` = 'sql';
UPDATE `gen_template` SET `template_content` = 'package ${packageName}.application.service.${moduleName}.dto;\n\nimport lombok.Data;\nimport java.io.Serializable;\n<#assign javaLangTypes = ["String", "Long", "Integer", "Boolean", "Double", "Float", "Short", "Byte", "Character"]>\n<#assign importPackages = {"LocalDateTime":"java.time", "LocalDate":"java.time", "LocalTime":"java.time", "Instant":"java.time", "ZonedDateTime":"java.time", "Duration":"java.time", "Period":"java.time", "BigDecimal":"java.math", "BigInteger":"java.math", "Date":"java.util", "Timestamp":"java.sql", "UUID":"java.util"}>\n<#assign imports = []>\n<#list columnsViews as property>\n    <#if !(["createBy", "createTime", "updateBy", "updateTime", "version", "deptId", "dept_id", "create_by", "create_time", "update_by", "update_time", "deleteStatus"]?seq_contains(property.propJavaEntity))>\n      <#assign type = property.propJavaType>\n      <#if !(javaLangTypes?seq_contains(type)) && importPackages[type]?? && !(imports?seq_contains(type))>\n        <#assign imports += [type]>\n      </#if>\n    </#if>\n</#list>\n<#list imports as imp>\nimport ${importPackages[imp]}.${imp};\n</#list>\n\n@Data\npublic class ${className}View implements Serializable {\n    <#assign excludeFields = ["createBy", "createTime", "updateBy", "updateTime", "version", "deptId", "dept_id", "create_by", "create_time", "update_by", "update_time", "deleteStatus"]>\n\n    <#list columnsViews as property>\n        <#if !(excludeFields?seq_contains(property.propJavaEntity))>\n    private ${property.propJavaType} ${property.propJavaEntity};\n\n        </#if>\n    </#list>\n}\n', `update_time` = NOW() WHERE `template_name` = 'view';
UPDATE `gen_template` SET `template_content` = 'package ${packageName}.domain.${moduleName};\n\nimport reactor.core.publisher.Mono;\n\nimport java.util.List;\n\npublic interface Wipe${className}DomainService {\n\n    Mono<Void> wipeByIds(List<Long> ids);\n\n}', `update_time` = NOW() WHERE `template_name` = 'wipeDomain';
UPDATE `gen_template` SET `template_content` = 'package ${packageName}.application.service.${moduleName};\n\nimport ${packageName}.domain.${moduleName}.Wipe${className}DomainService;\nimport ${packageName}.infrastructure.persistence.r2dbc.${className}Repository;\nimport lombok.RequiredArgsConstructor;\nimport org.springframework.stereotype.Component;\nimport reactor.core.publisher.Mono;\n\nimport java.util.List;\n\n@Component\n@RequiredArgsConstructor\npublic class Wipe${className}DomainServiceImpl implements Wipe${className}DomainService {\n\n    private final ${className}Repository repository;\n\n    @Override\n    public Mono<Void> wipeByIds(List<Long> ids) {\n        return repository.deleteAllById(ids);\n    }\n}', `update_time` = NOW() WHERE `template_name` = 'wipeDomainImpl';

